                onEnter = new[] { new FlagClause { key = "npc.keeper_met", op = FlagOp.SetTrue } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "1", speaker = "The Mythallar-Keeper",
                text = "*(She keeps her voice pitched to carry comfort, but the words she gives *you* are bare.)* You're not a noble. Nobles want to be *told.* You want to *know.* *(she adjusts a failing crystal; the amber stutters.)* So: the mythallar is dying. The Weave it draws from is *screaming* — something has wounded it at the root, far away, and the wound is racing toward us. In perhaps an hour, this engine stops, and when it stops, the Seventh Enclave stops being a *city in the sky* and becomes a *very large rock that was briefly confused about gravity.* *(calmly.)* There is no fixing it. The wound is not *here*; it is in the *Weave itself.* I have known for three hours. *(she turns to you fully.)* And in those three hours, I have told *four hundred souls* that everything is *fine.* I have *lied*, beautifully, continuously, to every frightened face that passed — and I want you to understand, before you judge me, that I did not lie to *save myself.* I lied because the truth buys *nothing* but an hour of *screaming*, and the lie buys an hour of *peace*, and if these are the last hours of four hundred people, I decided they would be *calm* ones. *(her composure does not crack.)* Tell me I was wrong. People do. I have an hour to find out if they're right.",
                choices = new[]
                {
                    new DialogueChoice { text = "[INSIGHT 18] \"You're not lying *to* them. You're lying *for* them — the way you'd hum to a child in a falling carriage. But you'll never know if you robbed someone of their last *true* hour: a goodbye they'd have said, if you'd let them be afraid.\"", nextNodeId = "robbed", checkAbility = Ability.Wisdom, checkDC = 18, failNodeId = "serene" },
                    new DialogueChoice { text = "[PERSUADE 17] \"There's a third path between panic and a pretty lie. The *quiet* truth — told to the few who can *act.* Not 'we're fine,' not 'we're doomed,' but 'we have an hour; spend it on what matters.' Let me help you tell *that* one.\"", nextNodeId = "third", checkAbility = Ability.Charisma, checkDC = 17, failNodeId = "serene" },
                    new DialogueChoice { text = "\"Who did *you* lie to that you loved, Keeper? There's a specific face behind this much composure. Tell me the one lie that's costing you.\"", nextNodeId = "face", effects = new[] { new FlagClause { key = "companion.naeve.approval", op = FlagOp.AddInt, amount = 3 } } },
                    new DialogueChoice { text = "\"You decided four hundred strangers should be calm instead of informed. That's a *god's* decision, made by a tired engineer. I won't tell you it was right. But I'll tell you it was *brave.*\"", nextNodeId = "brave", effects = new[] { new FlagClause { key = "companion.garrow.approval", op = FlagOp.AddInt, amount = 2 } } },
                }
            });

            g.nodes.Add(new DialogueNode
            {
                id = "robbed", speaker = "The Mythallar-Keeper",
                text = "*(For the first time the calm wavers — a single crack through perfect porcelain.)* ...The goodbye they'd have said. *(quietly.)* That. *That* is the thing that will follow me down. *(she steadies a failing valve by reflex.)* You see it exactly. I weighed *panic* against *peace* and chose peace — but there's a *third* thing in the scale I tried not to look at: the woman who, *told the truth*, would have run to her daughter's chamber and held her for the last hour. The man who would have *finally said it* to the one he never told. *(her hands still.)* My beautiful lie gave four hundred people a *calm* hour. It also stole, from some unknowable number of them, their *true* one — the goodbye, the confession, the last honest hour they'd have *chosen* if I'd let them be *afraid.* *(she meets your eyes, and the composure is a held thing now, not an effortless one.)* I will never know which I did to whom. That's the keeper's burden — I tend the engine, so I *decide*, and deciding means I'll fall not knowing if I gave peace or *robbed* goodbyes. *(softly.)* I think... I think I'd tell one true person, now. So that at least *one* soul gets the hour they'd choose. Will you help me pick who can *bear* it? I've spent my courage on the lying. I've little left for the truth.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.keeper_robbed", op = FlagOp.SetTrue }, new FlagClause { key = "act3.keeper_tells_truth", op = FlagOp.SetTrue }, new FlagClause { key = "act1.mercy_remembered", op = FlagOp.SetTrue }, new FlagClause { key = "companion.naeve.approval", op = FlagOp.AddInt, amount = 5 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "third", speaker = "The Mythallar-Keeper",
                text = "*(Her eyes sharpen — the engineer recognizing a better solution.)* The quiet truth. *(slowly.)* Not the *lie* that infantilizes and not the *truth* that stampedes. The truth told *narrow* — to the steward who can ready the children, the captain who can keep order, the priest who can shrive the dying. *(she sets down her tools.)* Gods. I framed it as *two* doors — *peace or panic* — and stood between them congratulating myself on choosing the kinder. But you're right, there was always a *third* door, and I didn't open it because the third door requires *trusting people with a piece of the weight*, and I — *(a thin breath)* — I am a *keeper.* I hold the engine *alone.* I hold the *secret* alone. Sharing is not in my training. *(she straightens, decided.)* But an hour is too little to hoard. Help me tell the *right* few — quietly, precisely — so that the last hour of the Seventh Enclave isn't a *lie* or a *riot* but a *city quietly putting its house in order.* Children gathered. Debts forgiven. Hands held by *choice.* *(fiercely calm.)* That's a better falling than I'd planned. I was going to give them a beautiful lie. You've offered me a chance to give them a *dignified truth.* Let's spend the hour well.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.keeper_third_path", op = FlagOp.SetTrue }, new FlagClause { key = "act3.keeper_quiet_truth", op = FlagOp.SetTrue }, new FlagClause { key = "act3.witnessed_fall", op = FlagOp.SetTrue }, new FlagClause { key = "companion.naeve.approval", op = FlagOp.AddInt, amount = 5 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "face", speaker = "The Mythallar-Keeper",
                text = "*(The composure holds, but her voice drops to something private.)* The one I love that I lied to. *(a long pause.)* ...My apprentice. Joss. Nineteen. He stood right *there* an hour ago — *(she nods at a spot by the engine)* — and he *saw* the amber stutter, and he's *clever*, he *knows* the readings, and he looked at me with the question already forming, and I — *(her hands tighten)* — I *smiled* and said *\"recalibration, Joss, fetch me the third lens.\"* And he *believed* me, because I'm his teacher, and he *trusts* me, and he *went to fetch the lens*, calm, while I let him walk away from his own last hour *learning a lie about valves.* *(quietly, the crack widening.)* He's the one. The face behind the composure. I can lie to four hundred strangers and keep my hands steady, but I sent the *boy I love like a son* to fetch a *lens* instead of telling him to *run home to his mother*, and *that* — *(she steadies herself on the engine)* — that one I cannot dress up as mercy. That one was just *cowardice* wearing a teacher's smile. *(she looks at you.)* Find Joss. Tell him the truth I couldn't. Let him spend his hour as *Joss*, not as the apprentice still believing in lenses. *Please.*",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.keeper_joss", op = FlagOp.SetTrue }, new FlagClause { key = "act3.find_joss", op = FlagOp.SetTrue }, new FlagClause { key = "act1.mercy_remembered", op = FlagOp.SetTrue }, new FlagClause { key = "companion.naeve.approval", op = FlagOp.AddInt, amount = 4 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "brave", speaker = "The Mythallar-Keeper",
                text = "*(Something in her eases, just slightly, at the word she didn't expect.)* Brave. *(a small, tired breath.)* No one's offered me *that* one. *Cold*, I've been called, in the three hours since I started lying — by the one other keeper who knows, who thinks I should *sound the alarm* and let the chips fall. *(she adjusts the dying engine.)* But sounding the alarm is *easy*, you see. It moves the weight *off* me and *onto* four hundred panicking souls. The *hard* thing — the thing I chose — was to *carry* the truth *alone* so that *they* wouldn't have to, and to *spend my own last hour lying* so that *theirs* could be *calm.* *(quietly.)* It may have been *wrong.* I've made my peace with possibly being *wrong.* What I could not bear was being *cowardly* — and you've named it *brave*, and I find that I needed, more than absolution, to be *seen* deciding the hard thing on purpose. *(she returns to the engine, steadier.)* Thank you. Now go — spend *your* hour better than I'm spending mine. Somebody in this city should get to fall *honestly.* I've chosen the lie. Don't *you* be calm. Be *true.* One of us should.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.keeper_brave", op = FlagOp.SetTrue }, new FlagClause { key = "companion.garrow.approval", op = FlagOp.AddInt, amount = 3 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "serene", speaker = "The Mythallar-Keeper",
                text = "*(The warm, certain mask slides back into place, seamless.)* You're very kind to take an interest in the *engineering.* *(she smiles the smile she gives the nobles.)* But truly — a momentary flux. The mythallar recalibrates; the evening continues; there is *nothing* to trouble yourself over. *(she turns back to the stuttering amber light, her composure a sealed door.)* Do enjoy what's left of the party. The salmon, I'm told, is exceptional. *(and she will not let you in again — she has chosen her lie, and she will keep it beautifully, alone, to the end.)*",
                autoNextNodeId = "close",
            });

            g.nodes.Add(new DialogueNode
            {
                id = "close", speaker = "The Mythallar-Keeper",
                text = "*(The keeper turns back to the dying heart of the city — tending an engine that cannot be saved, weighing four hundred calm lies against four hundred true goodbyes — and you carry away the cruelest arithmetic in Netheril: that mercy and cowardice can wear the very same smile, and the only soul who'll ever know which one she chose is the one who has to fall holding the answer.)*",
            });

            NpcNethKeeperDialogue = g;
        }

        private void BuildNpcNethWeavedeafDialogue()
        {
            var g = ScriptableObject.CreateInstance<DialogueGraph>();
            g.conversationId = "npc.neth.weavedeaf";
            g.startNodeId = "0";

            g.nodes.Add(new DialogueNode
            {
                id = "0", speaker = "A Calm Child in a Screaming City",
                text = "*(All around, arcanists clutch their heads and shriek — the Weave is dying, and to anyone attuned to it, its death is an unbearable *scream* tearing through the mind. Magelords weep blood. Apprentices claw at their ears. And in the middle of it, on a stone bench, a small girl sits *perfectly calm*, swinging her feet, watching the chaos with the mild interest of someone watching rain. She notices you noticing her stillness.)* You're not screaming either. *(she tilts her head.)* But you're not deaf like me. You hear it. You're just... *used* to terrible noises, I think. *(she pats the bench.)* Sit. You're the first grown-up who's looked at me instead of *through* me all day. Usually I'm the *broken* one. Today I'm the only one not bleeding from the ears, so. *(a small shrug.)* Funny how that works.",
                autoNextNodeId = "1",
                onEnter = new[] { new FlagClause { key = "npc.weavedeaf_met", op = FlagOp.SetTrue } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "1", speaker = "The Weave-Deaf Child",
                text = "*(She keeps swinging her feet, but her child's-voice carries something far older than her years.)* I was born Weave-deaf. It means I can't *hear* magic — can't feel the Weave, can't ever be a wizard, which in *Netheril* is like being born without a *face.* *(matter-of-fact.)* They tested me at four. The arcanist made the special light and asked what color it sang, and I said *lights don't sing*, and his face went all *sorry*, and after that everyone's face went all *sorry* whenever they looked at me. *Poor thing. Weave-deaf. Useless.* *(she watches a magelord collapse, screaming.)* And now the Weave is *dying*, and its dying is the loudest, worst sound there has ever been, and it's killing everyone who can *hear* it — driving them mad, stopping their hearts — and *I can't hear it at all.* *(she turns to you, and her calm is the eeriest thing in the falling city.)* The thing that made me *broken* my whole life is the only reason I'm the one person here who can still *think.* So I've been thinking. Somebody has to. Want to hear what the only calm person in a dying city worked out? I bet I'm right. Nobody ever lets me finish, usually.",
                choices = new[]
                {
                    new DialogueChoice { text = "[INSIGHT 16] \"Every day of your life they called you broken for not hearing the one thing everyone treasured. And the universe just proved that the 'defect' was the *survival.* You weren't *less.* You were *built for exactly this hour.*\"", nextNodeId = "built", checkAbility = Ability.Wisdom, checkDC = 16, failNodeId = "small" },
                    new DialogueChoice { text = "\"Tell me what you worked out. You're the only clear head in the sky and we're falling — I'd be a fool not to listen to the one person who isn't screaming.\"", nextNodeId = "worked" },
                    new DialogueChoice { text = "\"What's your name? I want to thank the right person when your clear head saves lives. Not 'the Weave-deaf girl.' *You.*\"", nextNodeId = "name", effects = new[] { new FlagClause { key = "companion.naeve.approval", op = FlagOp.AddInt, amount = 3 } } },
                    new DialogueChoice { text = "\"Come with me. The arcanists are useless and the engine's failing, but *you* can think, and I need someone who isn't drowning in the scream. Be my clear head.\"", nextNodeId = "come", effects = new[] { new FlagClause { key = "act3.weavedeaf_guide", op = FlagOp.SetTrue }, new FlagClause { key = "companion.garrow.approval", op = FlagOp.AddInt, amount = 2 } } },
                }
            });

            g.nodes.Add(new DialogueNode
            {
                id = "built", speaker = "The Weave-Deaf Child",
                text = "*(For the first time, the eerie calm cracks — into something much more like a child, eyes filling.)* ...Built for this hour. *(very quietly.)* You really think — *(she scrubs at her eyes, fierce.)* They said *broken* so many times I — I made it my *name*, almost. The broken one. The deaf one. The *sorry-faced* one. I stopped trying to be *good* at things because *what's the point*, a Netherese who can't touch the Weave is a *joke*, a *waste*, a — *(she swallows.)* And now everyone who could touch the Weave is *dying of it*, and I'm sitting here *fine*, and *thinking*, and you're telling me I wasn't *less* — I was *for* something — *(she draws a shaking breath, and the calm that returns is different now, owned.)* That changes it. That changes *everything* about every *sorry* face. They felt sorry for the one thing that's keeping me *alive* and *clear* while they bleed. *(she stands, small and suddenly certain.)* Then I'm not going to *waste* it being sad about being right too late. I'm going to *use* it. Come on. The clear head's getting up. There are people to pull out of the scream before we hit the ground, and I'm the only one who can walk through it without falling down. *Built for this hour.* I'm going to *believe* that. Watch me.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.weavedeaf_built", op = FlagOp.SetTrue }, new FlagClause { key = "act3.weavedeaf_guide", op = FlagOp.SetTrue }, new FlagClause { key = "act1.mercy_remembered", op = FlagOp.SetTrue }, new FlagClause { key = "companion.naeve.approval", op = FlagOp.AddInt, amount = 5 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "worked", speaker = "The Weave-Deaf Child",
                text = "*(She brightens — *finally*, someone's letting her finish — and lays it out with the crisp logic of a mind that thinks because no scream is stopping it.)* Right. So. Everyone's trying to *fix* the Weave or *escape* on teleport-magic, yes? *(she ticks it off on small fingers.)* Both *stupid.* The Weave's *dying* — you can't fix it, and every spell *fails* now, so teleporting just *splatters* you somewhere instead of *here.* *Magic is the thing that's broken.* So stop using magic. *(she points.)* The enclave is falling, but it's *falling*, not *vanished* — there's *time*, minutes, before the ground. And there are *non-magic* ways down. The cargo-gliders in the under-docks — *cloth and wood*, no Weave, the merchants use them when they don't want to pay the teleport-tax. They *still work*, because they were *never* magic. *(fiercely.)* Everyone's ignoring them because in *Netheril* you don't take the *peasant* way down — magic is for *lords*, gliders are for *cargo.* But the lords are all *bleeding from the ears*, and the *cargo-way* is the only way that *works* when the Weave is dead. *(she grins, sharp.)* The broken girl found the way out, and it's the way they were all too *proud* to look at. Funny how that works. Get people to the under-docks. I'll show you. I'm the only one who can read the way without a *guiding-spell* — because I *never had one.*",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.weavedeaf_plan", op = FlagOp.SetTrue }, new FlagClause { key = "act3.glider_escape", op = FlagOp.SetTrue }, new FlagClause { key = "act3.weavedeaf_guide", op = FlagOp.SetTrue }, new FlagClause { key = "companion.naeve.approval", op = FlagOp.AddInt, amount = 4 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "name", speaker = "The Weave-Deaf Child",
                text = "*(She blinks, genuinely startled.)* My name. *(slowly, like testing whether it's safe.)* ...It's Sefris. *(quietly.)* Most people don't ask. I'm *the Weave-deaf girl*, or *the Marsh's daughter*, or just *her*, the one you don't put in the wizard-school. *(she studies you.)* You asked like it *matters* which one I am. Like there's a *Sefris* worth thanking and not just a *defect* worth pitying. *(something steadies in her.)* Sefris. Yeah. *(a small, fierce smile.)* You know what — I like hearing it said like that. Like a *name* and not a *diagnosis.* *(she hops off the bench.)* Okay. *Sefris* is going to help you save some people, and when it's over and we're on the ground and not *under* it, you're going to tell whoever's left that *Sefris* did it. Not the deaf girl. *Sefris.* The one who could think when the whole sky was screaming. *(she offers a small hand to shake, solemn as a treaty.)* Deal?",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.weavedeaf_named", op = FlagOp.SetTrue }, new FlagClause { key = "act3.weavedeaf_guide", op = FlagOp.SetTrue }, new FlagClause { key = "companion.naeve.approval", op = FlagOp.AddInt, amount = 4 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "come", speaker = "The Weave-Deaf Child",
                text = "*(She hops off the bench immediately, as if she's been waiting all day to be *asked* to matter.)* *Finally.* *(she falls into step.)* Everyone else today either screamed at me or *prayed* at me or told me to *sit still and be brave*, and not *one* of them said *you can think, come help.* *(she glances up at you, sharp and pleased.)* You did. First one. *(matter-of-fact, walking into the chaos as the arcanists fall around her.)* I can walk through the scream — it's just *quiet* to me, I'll lead. I can find the ways the guiding-spells used to mark, because I learned every hall *by counting steps* instead of by magic — deaf kids do that. *(she takes your hand, small and certain.)* Stay close to the deaf girl, grown-up. Today the deaf girl's the one with *ears.* Come on. Let's go pull people out of a sky that won't stop screaming, and let's do it the *broken* way, which turns out to be the *only* way that *works.*",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.weavedeaf_joins", op = FlagOp.SetTrue }, new FlagClause { key = "act3.weavedeaf_guide", op = FlagOp.SetTrue }, new FlagClause { key = "companion.garrow.approval", op = FlagOp.AddInt, amount = 3 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "small", speaker = "The Weave-Deaf Child",
                text = "*(She shrugs, the calm sliding back over whatever you stirred.)* It's okay. You don't have to make it a *whole thing.* *(she swings her feet.)* I'm used to being the broken one. Today it's *useful* broken instead of *sad* broken, that's all. Doesn't mean anything. *(but she watches you a moment longer than her words allow, as if hoping you'll insist it *does* — and when you don't, she just nods, and goes back to watching the screaming city with her terrible, lonely calm.)*",
                autoNextNodeId = "close",
            });

            g.nodes.Add(new DialogueNode
            {
                id = "close", speaker = "The Weave-Deaf Child",
                text = "*(The Weave-deaf child sits — or rises — in the heart of the screaming enclave, the one clear mind in a city of bleeding wizards, and you carry away the truest law of the whole falling age: that the thing a proud world calls *broken* is so often the thing built, in secret, for the hour the world breaks — and that the deaf girl counting steps in the dark was always the one who'd know the way down.)*",
            });

            NpcNethWeavedeafDialogue = g;
        }
    }
}
